import pytest

def max_subarray_sum(arr: list) -> int:
    if not arr:
        return 0
    max_sum = current = arr[0]
    for num in arr[1:]:
        current = max(num, current + num)
        max_sum = max(max_sum, current)
    return max_sum

class TestMaxSubarraySum:

    # Happy path tests
    def test_positive_numbers(self):
        assert max_subarray_sum([1, 2, 3, 4, 5]) == 15

    def test_negative_numbers(self):
        assert max_subarray_sum([-1, -2, -3, -4, -5]) == -1

    def test_mixed_numbers(self):
        assert max_subarray_sum([-2, 1, -3, 4, -1, 2, 1, -5, 4]) == 6

    def test_single_positive_element(self):
        assert max_subarray_sum([5]) == 5

    def test_single_negative_element(self):
        assert max_subarray_sum([-3]) == -3

    def test_all_negative_except_one_positive(self):
        assert max_subarray_sum([-5, -2, -8, -1, 3, -4, -1]) == 3

    def test_alternating_positive_negative(self):
        assert max_subarray_sum([2, -1, 2, -1, 2]) == 4

    # Edge cases
    def test_empty_array(self):
        assert max_subarray_sum([]) == 0

    def test_two_elements_positive_first_larger(self):
        assert max_subarray_sum([5, -2]) == 5

    def test_two_elements_negative_first(self):
        assert max_subarray_sum([-1, 2]) == 2

    def test_two_elements_both_negative(self):
        assert max_subarray_sum([-3, -1]) == -1

    def test_zeros_in_array(self):
        assert max_subarray_sum([0, -1, 2, 0, -3, 4]) == 4

    def test_all_zeros(self):
        assert max_subarray_sum([0, 0, 0]) == 0

    def test_large_numbers(self):
        assert max_subarray_sum([1000000, -500000, 2000000, -1000000, 1500000]) == 3000000

    # Error cases - this function doesn't raise exceptions for invalid input
    # but we can test behavior with different input types
    def test_non_list_input(self):
        with pytest.raises(TypeError):
            max_subarray_sum("not a list")

    def test_non_list_input_numbers(self):
        with pytest.raises(TypeError):
            max_subarray_sum(123)

    def test_none_input(self):
        with pytest.raises(TypeError):
            max_subarray_sum(None)

    def test_list_with_non_numbers(self):
        with pytest.raises(TypeError):
            max_subarray_sum([1, 2, "three", 4])

    # Additional edge cases for complete coverage
    def test_consecutive_positive_numbers(self):
        assert max_subarray_sum([1, 2, 3, -10, 4, 5, 6]) == 15

    def test_all_negative_numbers_choose_least_negative(self):
        assert max_subarray_sum([-5, -2, -8, -1]) == -1

    def test_max_at_beginning(self):
        assert max_subarray_sum([10, -5, 2, -1]) == 10

    def test_max_at_end(self):
        assert max_subarray_sum([-5, 2, -1, 10]) == 10
